{
  "formal_minutes": {
    "meeting_info": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스를 목표로 한다."
      },
      {
        "topic": "packageName 불일치 대응 원칙",
        "decision": "packageName mismatch 발생 시 먼저 패키지 설정/계약을 확인하고, 계약이 잘못된 경우에 한해 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표(확정 릴리스 일정 아님)"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 검토 제안이 있었으나 확정 소유자는 지정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "선행조건 대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(가능 시)",
      "status": "소유자 미배정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 이전/직후 Minjun의 스모크 테스트 결과 수신 여부 확인",
      "금요일 12:00 KST까지 Doyun의 failure triage note 작성 완료 여부 확인",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과 확인",
      "README 설치 단계 검토 담당자 지정 필요 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "do_not_invent": [
      "고객 또는 외부 파트너 정보",
      "예산 정보",
      "보안 사고 정보",
      "프로덕션 장애 정보",
      "법무 승인 요구사항",
      "미지정 owner를 임의 지정",
      "미합의 deadline을 임의 확정"
    ]
  },
  "non_invention_rules": {
    "scope_rule": "인라인 공개-안전 합성 픽스처에 명시된 사실만 사용한다.",
    "explicit_non_facts": [
      "고객명 없음",
      "예산 언급 없음",
      "보안 사고 언급 없음",
      "프로덕션 장애 언급 없음",
      "법무 승인 요구 언급 없음"
    ],
    "inference_limits": [
      "확정되지 않은 의사결정은 open question 또는 non-decision으로만 표기",
      "담당자/기한 미정 항목은 미정 상태를 유지",
      "내부 스트레치 목표를 확정 릴리스 일정으로 승격하지 않음"
    ]
  }
}
